logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("MMOServer")


class ItemRarity(str, Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    owner_id: Optional[str] = None
    tradeable: bool = True
    metadata: dict = field(default_factory=dict)

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "owner_id": self.owner_id,
            "tradeable": self.tradeable,
            "metadata": self.metadata,
        }


@dataclass
class TradeOffer:
    trade_id: str
    from_player_id: str
    to_player_id: str
    offered_items: list  # item_ids from initiator
    requested_items: list  # item_ids from target
    status: str = "pending"  # pending, accepted, declined, cancelled, completed
    created_at: float = field(default_factory=time.time)
    expires_at: float = field(default_factory=lambda: time.time() + 300)  # 5 min expiry

    def to_dict(self):
        return {
            "trade_id": self.trade_id,
            "from_player_id": self.from_player_id,
            "to_player_id": self.to_player_id,
            "offered_items": self.offered_items,
            "requested_items": self.requested_items,
            "status": self.status,
            "created_at": self.created_at,
            "expires_at": self.expires_at,
        }


@dataclass
class Player:
    player_id: str
    username: str
    inventory: Dict[str, Item] = field(default_factory=dict)
    max_inventory_size: int = 50
    websocket: Optional[object] = None
    active_trade_id: Optional[str] = None

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "username": self.username,
            "inventory": {k: v.to_dict() for k, v in self.inventory.items()},
            "max_inventory_size": self.max_inventory_size,
            "active_trade_id": self.active_trade_id,
        }


class InventoryManager:
    """Manages all item operations with proper locking for concurrency."""

    def __init__(self):
        self._items: Dict[str, Item] = {}
        self._item_locks: Dict[str, asyncio.Lock] = {}
        self._global_lock = asyncio.Lock()

    async def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        async with self._global_lock:
            if item_id not in self._item_locks:
                self._item_locks[item_id] = asyncio.Lock()
            return self._item_locks[item_id]

    def register_item(self, item: Item):
        self._items[item.item_id] = item

    def get_item(self, item_id: str) -> Optional[Item]:
        return self._items.get(item_id)

    async def transfer_item(self, item_id: str, from_player: Player, to_player: Player) -> bool:
        """Transfer a single item between players with proper locking."""
        lock = await self._get_item_lock(item_id)
        async with lock:
            item = self._items.get(item_id)
            if item is None:
                logger.warning(f"Item {item_id} not found")
                return False
            if not item.tradeable:
                logger.warning(f"Item {item_id} is not tradeable")
                return False
            if item.owner_id != from_player.player_id:
                logger.warning(
                    f"Item {item_id} not owned by {from_player.player_id} "
                    f"(owned by {item.owner_id})"
                )
                return False
            if item_id not in from_player.inventory:
                logger.warning(f"Item {item_id} not in {from_player.username}'s inventory")
                return False
            if len(to_player.inventory) >= to_player.max_inventory_size:
                logger.warning(f"{to_player.username}'s inventory is full")
                return False

            # Perform transfer
            del from_player.inventory[item_id]
            item.owner_id = to_player.player_id
            to_player.inventory[item_id] = item

            logger.info(
                f"Transferred item '{item.name}' ({item_id}) "
                f"from {from_player.username} to {to_player.username}"
            )
            return True

    async def batch_transfer(
        self,
        items_a_to_b: list,
        items_b_to_a: list,
        player_a: Player,
        player_b: Player,
    ) -> bool:
        """
        Atomically transfer items between two players (for trades).
        Acquires locks in sorted order to prevent deadlocks.
        """
        all_item_ids = sorted(set(items_a_to_b + items_b_to_a))
        locks = []
        for item_id in all_item_ids:
            lock = await self._get_item_lock(item_id)
            locks.append((item_id, lock))

        # Acquire all locks in sorted order
        for _, lock in locks:
            await lock.acquire()

        try:
            # Validate all transfers first
            for item_id in items_a_to_b:
                item = self._items.get(item_id)
                if item is None or not item.tradeable:
                    logger.warning(f"Validation failed: item {item_id} invalid or not tradeable")
                    return False
                if item.owner_id != player_a.player_id or item_id not in player_a.inventory:
                    logger.warning(f"Validation failed: item {item_id} not owned by {player_a.username}")
                    return False

            for item_id in items_b_to_a:
                item = self._items.get(item_id)
                if item is None or not item.tradeable:
                    logger.warning(f"Validation failed: item {item_id} invalid or not tradeable")
                    return False
                if item.owner_id != player_b.player_id or item_id not in player_b.inventory:
                    logger.warning(f"Validation failed: item {item_id} not owned by {player_b.username}")
                    return False

            # Check inventory capacity
            a_net_change = len(items_b_to_a) - len(items_a_to_b)
            b_net_change = len(items_a_to_b) - len(items_b_to_a)

            if len(player_a.inventory) + a_net_change > player_a.max_inventory_size:
                logger.warning(f"{player_a.username} would exceed inventory capacity")
                return False
            if len(player_b.inventory) + b_net_change > player_b.max_inventory_size:
                logger.warning(f"{player_b.username} would exceed inventory capacity")
                return False

            # Execute all transfers atomically
            for item_id in items_a_to_b:
                item = self._items[item_id]
                del player_a.inventory[item_id]
                item.owner_id = player_b.player_id
                player_b.inventory[item_id] = item

            for item_id in items_b_to_a:
                item = self._items[item_id]
                del player_b.inventory[item_id]
                item.owner_id = player_a.player_id
                player_a.inventory[item_id] = item

            logger.info(
                f"Batch transfer completed: {len(items_a_to_b)} items "
                f"{player_a.username}->{player_b.username}, "
                f"{len(items_b_to_a)} items {player_b.username}->{player_a.username}"
            )
            return True

        finally:
            for _, lock in locks:
                lock.release()


class TradeManager:
    """Manages trade offers and their lifecycle."""

    def __init__(self, inventory_manager: InventoryManager):
        self._trades: Dict[str, TradeOffer] = {}
        self._trade_lock = asyncio.Lock()
        self._inventory_manager = inventory_manager

    async def create_trade(
        self,
        from_player: Player,
        to_player: Player,
        offered_items: list,
        requested_items: list,
    ) -> Optional[TradeOffer]:
        async with self._trade_lock:
            if from_player.active_trade_id is not None:
                logger.warning(f"{from_player.username} already has an active trade")
                return None
            if to_player.active_trade_id is not None:
                logger.warning(f"{to_player.username} already has an active trade")
                return None

            # Validate offered items belong to from_player
            for item_id in offered_items:
                if item_id not in from_player.inventory:
                    logger.warning(f"Item {item_id} not in {from_player.username}'s inventory")
                    return None
                item = from_player.inventory[item_id]
                if not item.tradeable:
                    logger.warning(f"Item {item_id} is not tradeable")
                    return None

            # Validate requested items belong to to_player
            for item_id in requested_items:
                if item_id not in to_player.inventory:
                    logger.warning(f"Item {item_id} not in {to_player.username}'s inventory")
                    return None
                item = to_player.inventory[item_id]
                if not item.tradeable:
                    logger.warning(f"Item {item_id} is not tradeable")
                    return None

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                from_player_id=from_player.player_id,
                to_player_id=to_player.player_id,
                offered_items=offered_items,
                requested_items=requested_items,
            )
            self._trades[trade_id] = trade
            from_player.active_trade_id = trade_id
            to_player.active_trade_id = trade_id

            logger.info(
                f"Trade {trade_id} created: {from_player.username} <-> {to_player.username}"
            )
            return trade

    async def accept_trade(
        self, trade_id: str, accepting_player_id: str, players: Dict[str, Player]
    ) -> Optional[TradeOffer]:
        async with self._trade_lock:
            trade = self._trades.get(trade_id)
            if trade is None:
                return None
            if trade.status != "pending":
                logger.warning(f"Trade {trade_id} is not pending (status: {trade.status})")
                return None
            if trade.to_player_id != accepting_player_id:
                logger.warning(f"Only the target player can accept the trade")
                return None
            if time.time() > trade.expires_at:
                trade.status = "expired"
                self._clear_active_trades(trade, players)
                return None

            from_player = players.get(trade.from_player_id)
            to_player = players.get(trade.to_player_id)

            if from_player is None or to_player is None:
                trade.status = "cancelled"
                self._clear_active_trades(trade, players)
                return None

            # Perform the atomic batch transfer
            success = await self._inventory_manager.batch_transfer(
                items_a_to_b=trade.offered_items,
                items_b_to_a=trade.requested_items,
                player_a=from_player,
                player_b=to_player,
            )

            if success:
                trade.status = "completed"
                logger.info(f"Trade {trade_id} completed successfully")
            else:
                trade.status = "failed"
                logger.warning(f"Trade {trade_id} failed during transfer")

            self._clear_active_trades(trade, players)
            return trade

    async def decline_trade(
        self, trade_id: str, declining_player_id: str, players: Dict[str, Player]
    ) -> Optional[TradeOffer]:
        async with self._trade_lock:
            trade = self._trades.get(trade_id)
            if trade is None:
                return None
            if trade.status != "pending":
                return None
            if declining_player_id not in (trade.from_player_id, trade.to_player_id):
                return None

            trade.status = "declined"
            self._clear_active_trades(trade, players)
            logger.info(f"Trade {trade_id} declined by {declining_player_id}")
            return trade

    async def cancel_trade(
        self, trade_id: str, cancelling_player_id: str, players: Dict[str, Player]
    ) -> Optional[TradeOffer]:
        async with self._trade_lock:
            trade = self._trades.get(trade_id)
            if trade is None:
                return None
            if trade.status != "pending":
                return None
            if trade.from_player_id != cancelling_player_id:
                return None

            trade.status = "cancelled"
            self._clear_active_trades(trade, players)
            logger.info(f"Trade {trade_id} cancelled by {cancelling_player_id}")
            return trade

    def _clear_active_trades(self, trade: TradeOffer, players: Dict[str, Player]):
        from_player = players.get(trade.from_player_id)
        to_player = players.get(trade.to_player_id)
        if from_player and from_player.active_trade_id == trade.trade_id:
            from_player.active_trade_id = None
        if to_player and to_player.active_trade_id == trade.trade_id:
            to_player.active_trade_id = None

    async def cleanup_expired_trades(self, players: Dict[str, Player]):
        """Periodic cleanup of expired trades."""
        async with self._trade_lock:
            now = time.time()
            expired = [
                tid
                for tid, t in self._trades.items()
                if t.status == "pending" and now > t.expires_at
            ]
            for trade_id in expired:
                trade = self._trades[trade_id]
                trade.status = "expired"
                self._clear_active_trades(trade, players)
                logger.info(f"Trade {trade_id} expired")


class GameServer:
    """Main MMO game server handling websocket connections and game logic."""

    def __init__(self, host: str = "localhost", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.ws_to_player: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.inventory_manager = InventoryManager()
        self.trade_manager = TradeManager(self.inventory_manager)
        self._connection_lock = asyncio.Lock()

    def _create_starter_items(self, player: Player):
        """Give new players some starter items."""
        starter_items = [
            Item(
                item_id=str(uuid.uuid4()),
                name="Wooden Sword",
                rarity=ItemRarity.COMMON,
                owner_id=player.player_id,
                metadata={"damage": 5, "type": "weapon"},
            ),
            Item(
                item_id=str(uuid.uuid4()),
                name="Leather Armor",
                rarity=ItemRarity.COMMON,
                owner_id=player.player_id,
                metadata={"defense": 3, "type": "armor"},
            ),
            Item(
                item_id=str(uuid.uuid4()),
                name="Health Potion",
                rarity=ItemRarity.COMMON,
                owner_id=player.player_id,
                metadata={"heal": 50, "type": "consumable"},
            ),
            Item(
                item_id=str(uuid.uuid4()),
                name="Gold Coin",
                rarity=ItemRarity.UNCOMMON,
                owner_id=player.player_id,
                tradeable=True,
                metadata={"value": 100, "type": "currency"},
            ),
            Item(
                item_id=str(uuid.uuid4()),
                name="Mystic Gem",
                rarity=ItemRarity.RARE,
                owner_id=player.player_id,
                metadata={"power": 25, "type": "material"},
            ),
        ]
        for item in starter_items:
            player.inventory[item.item_id] = item
            self.inventory_manager.register_item(item)

    async def _send_message(self, websocket, message: dict):
        try:
            await websocket.send(json.dumps(message))
        except websockets.exceptions.ConnectionClosed:
            logger.warning("Failed to send message: connection closed")

    async def _broadcast(self, message: dict, exclude: Optional[Set[str]] = None):
        exclude = exclude or set()
        tasks = []
        for player_id, ws in self.connections.items():
            if player_id not in exclude:
                tasks.append(self._send_message(ws, message))
        if tasks:
            await asyncio.gather(*tasks, return_exceptions=True)

    async def _notify_player(self, player_id: str, message: dict):
        ws = self.connections.get(player_id)
        if ws:
            await self._send_message(ws, message)

    async def handle_login(self, websocket, data: dict) -> Optional[Player]:
        username = data.get("username", "").strip()
        if not username:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Username is required",
            })
            return None

        async with self._connection_lock:
            # Check if username is already taken
            for pid, p in self.players.items():
                if p.username == username and pid in self.connections:
                    await self._send_message(websocket, {
                        "type": "error",
                        "message": f"Username '{username}' is already taken",
                    })
                    return None

            player_id = str(uuid.uuid4())
            player = Player(
                player_id=player_id,
                username=username,
                websocket=websocket,
            )
            self._create_starter_items(player)
            self.players[player_id] = player
            self.connections[player_id] = websocket
            self.ws_to_player[websocket] = player_id

        logger.info(f"Player '{username}' ({player_id}) logged in")

        await self._send_message(websocket, {
            "type": "login_success",
            "player": player.to_dict(),
        })

        await self._broadcast(
            {
                "type": "player_joined",
                "player_id": player_id,
                "username": username,
            },
            exclude={player_id},
        )

        # Send list of online players
        online_players = [
            {"player_id": pid, "username": p.username}
            for pid, p in self.players.items()
            if pid in self.connections and pid != player_id
        ]
        await self._send_message(websocket, {
            "type": "online_players",
            "players": online_players,
        })

        return player

    async def handle_get_inventory(self, player: Player, websocket):
        await self._send_message(websocket, {
            "type": "inventory",
            "items": [item.to_dict() for item in player.inventory.values()],
            "capacity": f"{len(player.inventory)}/{player.max_inventory_size}",
        })

    async def handle_inspect_player(self, player: Player, websocket, data: dict):
        target_id = data.get("target_player_id")
        target = self.players.get(target_id)
        if target is None:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Player not found",
            })
            return

        # Only show tradeable items to other players
        tradeable_items = [
            item.to_dict()
            for item in target.inventory.values()
            if item.tradeable
        ]
        await self._send_message(websocket, {
            "type": "player_inventory",
            "player_id": target_id,
            "username": target.username,
            "tradeable_items": tradeable_items,
        })

    async def handle_trade_offer(self, player: Player, websocket, data: dict):
        target_id = data.get("target_player_id")
        offered_items = data.get("offered_items", [])
        requested_items = data.get("requested_items", [])

        if not target_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Target player ID is required",
            })
            return

        if target_id == player.player_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Cannot trade with yourself",
            })
            return

        target = self.players.get(target_id)
        if target is None or target_id not in self.connections:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Target player not found or offline",
            })
            return

        if not offered_items and not requested_items:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Trade must include at least one item",
            })
            return

        trade = await self.trade_manager.create_trade(
            from_player=player,
            to_player=target,
            offered_items=offered_items,
            requested_items=requested_items,
        )

        if trade is None:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Failed to create trade. Check if you or the target already have an active trade, and that all items are valid.",
            })
            return

        # Notify both players
        await self._send_message(websocket, {
            "type": "trade_created",
            "trade": trade.to_dict(),
        })

        offered_details = [
            player.inventory[iid].to_dict()
            for iid in offered_items
            if iid in player.inventory
        ]
        requested_details = [
            target.inventory[iid].to_dict()
            for iid in requested_items
            if iid in target.inventory
        ]

        await self._notify_player(target_id, {
            "type": "trade_offer_received",
            "trade": trade.to_dict(),
            "from_username": player.username,
            "offered_items_details": offered_details,
            "requested_items_details": requested_details,
        })

    async def handle_trade_accept(self, player: Player, websocket, data: dict):
        trade_id = data.get("trade_id")
        if not trade_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Trade ID is required",
            })
            return

        trade = await self.trade_manager.accept_trade(
            trade_id=trade_id,
            accepting_player_id=player.player_id,
            players=self.players,
        )

        if trade is None:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Failed to accept trade. It may have expired or been cancelled.",
            })
            return

        if trade.status == "completed":
            from_player = self.players.get(trade.from_player_id)
            to_player = self.players.get(trade.to_player_id)

            # Notify both players of completion
            for p in [from_player, to_player]:
                if p:
                    await self._notify_player(p.player_id, {
                        "type": "trade_completed",
                        "trade": trade.to_dict(),
                        "your_inventory": [
                            item.to_dict() for item in p.inventory.values()
                        ],
                    })

            logger.info(
                f"Trade {trade_id} completed between "
                f"{from_player.username if from_player else '?'} and "
                f"{to_player.username if to_player else '?'}"
            )
        else:
            await self._send_message(websocket, {
                "type": "trade_failed",
                "trade": trade.to_dict(),
                "message": "Trade transfer failed. Items may have changed.",
            })
            await self._notify_player(trade.from_player_id, {
                "type": "trade_failed",
                "trade": trade.to_dict(),
                "message": "Trade transfer failed.",
            })

    async def handle_trade_decline(self, player: Player, websocket, data: dict):
        trade_id = data.get("trade_id")
        if not trade_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Trade ID is required",
            })
            return

        trade = await self.trade_manager.decline_trade(
            trade_id=trade_id,
            declining_player_id=player.player_id,
            players=self.players,
        )

        if trade is None:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Failed to decline trade.",
            })
            return

        # Notify both players
        other_id = (
            trade.to_player_id
            if player.player_id == trade.from_player_id
            else trade.from_player_id
        )
        await self._send_message(websocket, {
            "type": "trade_declined",
            "trade": trade.to_dict(),
        })
        await self._notify_player(other_id, {
            "type": "trade_declined",
            "trade": trade.to_dict(),
            "declined_by": player.username,
        })

    async def handle_trade_cancel(self, player: Player, websocket, data: dict):
        trade_id = data.get("trade_id")
        if not trade_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Trade ID is required",
            })
            return

        trade = await self.trade_manager.cancel_trade(
            trade_id=trade_id,
            cancelling_player_id=player.player_id,
            players=self.players,
        )

        if trade is None:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Failed to cancel trade.",
            })
            return

        await self._send_message(websocket, {
            "type": "trade_cancelled",
            "trade": trade.to_dict(),
        })
        await self._notify_player(trade.to_player_id, {
            "type": "trade_cancelled",
            "trade": trade.to_dict(),
            "cancelled_by": player.username,
        })

    async def handle_gift_item(self, player: Player, websocket, data: dict):
        """Direct item gift (one-way transfer) without trade negotiation."""
        target_id = data.get("target_player_id")
        item_id = data.get("item_id")

        if not target_id or not item_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Target player ID and item ID are required",
            })
            return

        if target_id == player.player_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Cannot gift items to yourself",
            })
            return

        target = self.players.get(target_id)
        if target is None or target_id not in self.connections:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Target player not found or offline",
            })
            return

        success = await self.inventory_manager.transfer_item(
            item_id=item_id,
            from_player=player,
            to_player=target,
        )

        if success:
            item = self.inventory_manager.get_item(item_id)
            await self._send_message(websocket, {
                "type": "gift_sent",
                "item": item.to_dict() if item else {"item_id": item_id},
                "to_player": target.username,
            })
            await self._notify_player(target_id, {
                "type": "gift_received",
                "item": item.to_dict() if item else {"item_id": item_id},
                "from_player": player.username,
            })
        else:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Failed to gift item. Check ownership and target inventory space.",
            })

    async def handle_drop_item(self, player: Player, websocket, data: dict):
        """Remove an item from player's inventory (destroy it)."""
        item_id = data.get("item_id")
        if not item_id:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Item ID is required",
            })
            return

        if item_id not in player.inventory:
            await self._send_message(websocket, {
                "type": "error",
                "message": "Item not found in your inventory",
            })
            return

        item = player.inventory.pop(item_id)
        item.owner_id = None
        logger.info(f"{player.username} dropped item '{item.name}' ({item_id})")

        await self._send_message(websocket, {
            "type": "item_dropped",
            "item": item.to_dict(),
        })

    async def handle_connection(self, websocket):
        player = None
        try:
            async for raw_message in websocket:
                try:
                    data = json.loads(raw_message)
                except json.JSONDecodeError:
                    await self._send_message(websocket, {
                        "type": "error",
                        "message": "Invalid JSON",
                    })
                    continue

                msg_type = data.get("type")

                if msg_type == "login":
                    if player is not None:
                        await self._send_message(websocket, {
                            "type": "error",
                            "message": "Already logged in",
                        })
                        continue
                    player = await self.handle_login(websocket, data)
                    continue

                # All other actions require authentication
                if player is None:
                    await self._send_message(websocket, {
                        "type": "error",
                        "message": "You must login first",
                    })
                    continue

                if msg_type == "get_inventory":
                    await self.handle_get_inventory(player, websocket)
                elif msg_type == "inspect_player":
                    await self.handle_inspect_player(player, websocket, data)
                elif msg_type == "trade_offer":
                    await self.handle_trade_offer(player, websocket, data)
                elif msg_type == "trade_accept":
                    await self.handle_trade_accept(player, websocket, data)
                elif msg_type == "trade_decline":
                    await self.handle_trade_decline(player, websocket, data)
                elif msg_type == "trade_cancel":
                    await self.handle_trade_cancel(player, websocket, data)
                elif msg_type == "gift_item":
                    await self.handle_gift_item(player, websocket, data)
                elif msg_type == "drop_item":
                    await self.handle_drop_item(player, websocket, data)
                elif msg_type == "get_online_players":
                    online_players = [
                        {"player_id": pid, "username": p.username}
                        for pid, p in self.players.items()
                        if pid in self.connections
                    ]
                    await self._send_message(websocket, {
                        "type": "online_players",
                        "players": online_players,
                    })
                elif msg_type == "chat":
                    # Simple global chat
                    message_text = data.get("message", "")
                    if message_text:
                        await self._broadcast({
                            "type": "chat",
                            "from": player.username,
                            "message": message_text,
                        })
                else:
                    await self._send_message(websocket, {
                        "type": "error",
                        "message": f"Unknown message type: {msg_type}",
                    })

        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection closed for {player.username if player else 'unknown'}")
        except Exception as e:
            logger.exception(f"Error handling connection: {e}")
        finally:
            if player:
                await self._handle_disconnect(player, websocket)

    async def _handle_disconnect(self, player: Player, websocket):
        async with self._connection_lock:
            if player.player_id in self.connections:
                del self.connections[player.player_id]
            if websocket in self.ws_to_player:
                del self.ws_to_player[websocket]

        # Cancel any active trade
        if player.active_trade_id:
            trade = await self.trade_manager.cancel_trade(
                trade_id=player.active_trade_id,
                cancelling_player_id=player.player_id,
                players=self.players,
            )
            if trade:
                other_id = (
                    trade.to_player_id
                    if player.player_id == trade.from_player_id
                    else trade.from_player_id
                )
                await self._notify_player(other_id, {
                    "type": "trade_cancelled",
                    "trade": trade.to_dict(),
                    "reason": f"{player.username} disconnected",
                })

        logger.info(f"Player '{player.username}' ({player.player_id}) disconnected")

        await self._broadcast({
            "type": "player_left",
            "player_id": player.player_id,
            "username": player.username,
        })

    async def _trade_cleanup_loop(self):
        """Periodically clean up expired trades."""
        while True:
            await asyncio.sleep(30)
            try:
                await self.trade_manager.cleanup_expired_trades(self.players)
            except Exception as e:
                logger.exception(f"Error in trade cleanup: {e}")

    async def start(self):
        logger.info(f"Starting MMO Game Server on {self.host}:{self.port}")

        # Start background tasks
        cleanup_task = asyncio.create_task(self._trade_cleanup_loop())

        async with websockets.serve(
            self.handle_connection,
            self.host,
            self.port,
            ping_interval=20,
            ping_timeout=20,
        ):
            logger.info(f"Server running on ws://{self.host}:{self.port}")
            await asyncio.Future()  # Run forever


async def demo_client(username: str, actions: list):
    """Demo client for testing the server."""
    uri = "ws://localhost:8765"
    async with websockets.connect(uri) as websocket:
        # Login
        await websocket.send(json.dumps({
            "type": "login",
            "username": username,
        }))
        response = json.loads(await websocket.recv())
        print(f"[{username}] Login response: {response['type']}")

        if response["type"] != "login_success":
            print(f"[{username}] Login failed: {response}")
            return None

        player_data = response["player"]

        # Consume any additional messages (online players, etc.)
        try:
            while True:
                extra = await asyncio.wait_for(websocket.recv(), timeout=0.5)
                msg = json.loads(extra)
                print(f"[{username}] Received: {msg['type']}")
        except asyncio.TimeoutError:
            pass

        for action in actions:
            await websocket.send(json.dumps(action))
            try:
                while True:
                    resp = await asyncio.wait_for(websocket.recv(), timeout=1.0)
                    msg = json.loads(resp)
                    print(f"[{username}] Received: {json.dumps(msg, indent=2)}")
            except asyncio.TimeoutError:
                pass

        return player_data


async def run_demo():
    """Run a demo showing two players trading."""
    print("=" * 60)
    print("MMO Game Server Demo")
    print("=" * 60)

    server = GameServer()
    server_task = asyncio.create_task(server.start())

    await asyncio.sleep(1)  # Wait for server to start

    # Connect Player 1
    uri = "ws://localhost:8765"

    async with websockets.connect(uri) as ws1, websockets.connect(uri) as ws2:
        # Login Player 1
        await ws1.send(json.dumps({"type": "login", "username": "Alice"}))
        p1_response = json.loads(await ws1.recv())
        p1_data = p1_response["player"]
        print(f"\nAlice logged in with {len(p1_data['inventory'])} items")

        # Drain extra messages
        try:
            while True:
                await asyncio.wait_for(ws1.recv(), timeout=0.3)
        except asyncio.TimeoutError:
            pass

        # Login Player 2
        await ws2.send(json.dumps({"type": "login", "username": "Bob"}))
        p2_response = json.loads(await ws2.recv())
        p2_data = p2_response["player"]
        print(f"Bob logged in with {len(p2_data['inventory'])} items")

        # Drain extra messages
        for ws in [ws1, ws2]:
            try:
                while True:
                    await asyncio.wait_for(ws.recv(), timeout=0.3)
            except asyncio.TimeoutError:
                pass

        # Alice's items
        alice_items = list(p1_data["inventory"].keys())
        bob_items = list(p2_data["inventory"].keys())

        print(f"\nAlice's items: {[p1_data['inventory'][i]['name'] for i in alice_items]}")
        print(f"Bob's items: {[p2_data['inventory'][i]['name'] for i in bob_items]}")

        # Alice offers to trade her first item for Bob's first item
        print(f"\n--- Alice proposes a trade ---")
        print(f"Offering: {p1_data['inventory'][alice_items[0]]['name']}")
        print(f"Requesting: {p2_data['inventory'][bob_items[0]]['name']}")

        await ws1.send(json.dumps({
            "type": "trade_offer",
            "target_player_id": p2_data["player_id"],
            "offered_items": [alice_items[0]],
            "requested_items": [bob_items[0]],
        }))

        # Alice receives trade_created
        trade_created = json.loads(await ws1.recv())
        print(f"\nAlice received: {trade_created['type']}")
        trade_id = trade_created["trade"]["trade_id"]

        # Bob receives trade offer
        trade_offer = json.loads(await ws2.recv())
        print(f"Bob received: {trade_offer['type']}")
        print(f"  Offered: {[i['name'] for i in trade_offer['offered_items_details']]}")
        print(f"  Requested: {[i['name'] for i in trade_offer['requested_items_details']]}")

        # Bob accepts the trade
        print(f"\n--- Bob accepts the trade ---")
        await ws2.send(json.dumps({
            "type": "trade_accept",
            "trade_id": trade_id,
        }))

        # Both receive trade_completed
        for name, ws in [("Bob", ws2), ("Alice", ws1)]:
            resp = json.loads(await ws.recv())
            print(f"\n{name} received: {resp['type']}")
            if resp["type"] == "trade_completed":
                inv_names = [i["name"] for i in resp["your_inventory"]]
                print(f"  {name}'s inventory: {inv_names}")

        # Test gifting
        print(f"\n--- Alice gifts an item to Bob ---")
        await ws1.send(json.dumps({"type": "get_inventory"}))
        inv_resp = json.loads(await ws1.recv())
        alice_current_items = inv_resp["items"]
        if alice_current_items:
            gift_item = alice_current_items[0]
            print(f"Gifting: {gift_item['name']}")
            await ws1.send(json.dumps({
                "type": "gift_item",
                "target_player_id": p2_data["player_id"],
                "item_id": gift_item["item_id"],
            }))

            gift_sent = json.loads(await ws1.recv())
            print(f"Alice received: {gift_sent['type']}")

            gift_received = json.loads(await ws2.recv())
            print(f"Bob received: {gift_received['type']} - {gift_received.get('item', {}).get('name')}")

        print("\n" + "=" * 60)
        print("Demo completed successfully!")
        print("=" * 60)

    server_task.cancel()


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "demo":
        asyncio.run(run_demo())
    else:
        server = GameServer()
        asyncio.run(server.start())